+function spawnMole() {
+    if (!gameActive || activeMoles.size >= DIFF.maxMoles) return;
+
+    const available = [];
+    for (let i = 0; i < HOLES; i++) {
+        if (!activeMoles.has(i)) available.push(i);
+    }
+    if (!available.length) return;
+
+    const idx = available[Math.floor(Math.random() * available.length)];
+    showMole(idx);
+}
+
+function showMole(idx) {
+    activeMoles.add(idx);
+    const hole = holeEls[idx];
+    hole.classList.remove('whacked');
+    hole.classList.add('up');
+
+    // Auto-hide after random duration
+    const t = setTimeout(() => {
+        if (activeMoles.has(idx) && !holeEls[idx].classList.contains('whacked')) {
+            hideMole(idx);
+        }
+    }, moleDuration());
+    moleFades.set(idx, t);
+}
+
+function hideMole(idx) {
+    activeMoles.delete(idx);
+    moleFades.delete(idx);
+    holeEls[idx].classList.remove('up', 'whacked');
+}
+
+// ── Click handling ────────────────────────────────────────────────────────
+function onHoleClick(idx) {
+    if (!gameActive) return;
+
+    if (activeMoles.has(idx) && !holeEls[idx].classList.contains('whacked')) {
+        // Hit!
+        score += POINTS_PER_HIT;
+        scoreVal.textContent = score;
+
+        holeEls[idx].classList.add('whacked');
+        sfxWhack();
+
+        // Cancel the auto-hide timeout
+        clearTimeout(moleFades.get(idx));
+        moleFades.delete(idx);
+
+        // Score popup
+        const popup = document.createElement('div');
+        popup.className  = 'score-popup';
+        popup.textContent = `+${POINTS_PER_HIT}`;
+        holeEls[idx].appendChild(popup);
+        setTimeout(() => popup.remove(), 560);
+
+        // Retract after whack animation
+        setTimeout(() => hideMole(idx), 320);
+    } else if (!activeMoles.has(idx)) {
+        sfxMiss();
+    }
+}
+
+// ── Controls ──────────────────────────────────────────────────────────────
+startBtn.addEventListener('click', startGame);
+
+muteBtn.addEventListener('click', () => {
+    muted = !muted;
+    muteBtn.classList.toggle('muted', muted);
+    muteBtn.textContent = muted ? '✕ SFX' : '♪ SFX';
+});
+</script>
+</body>
+</html>
